package main

import (
	"context"
	"fmt"
	"log"
	"net"
	"sync"
	"time"

	"github.com/google/uuid"
	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/timestamppb"

	pb "github.com/your-org/your-repo/pkg/transaction" // Adjust import path
)

const (
	port = ":50051"
)

// server is used to implement transaction.TransactionServiceServer.
type server struct {
	pb.UnimplementedTransactionServiceServer
	mu              sync.Mutex
	accountBalances map[string]float64
	transactions    map[string]*pb.CreateTransactionResponse
}

func newServer() *server {
	return &server{
		accountBalances: make(map[string]float64),
		transactions:    make(map[string]*pb.CreateTransactionResponse),
	}
}

// CreateTransaction implements transaction.TransactionServiceServer
func (s *server) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	transactionID := uuid.New().String()
	now := timestamppb.New(time.Now())

	resp := &pb.CreateTransactionResponse{
		TransactionId: transactionID,
		Status:        "FAILED",
		Message:       "Transaction failed due to insufficient funds or invalid accounts.",
		Timestamp:     now,
	}

	// Initialize accounts if they don't exist
	if _, ok := s.accountBalances[req.FromAccountId]; !ok {
		s.accountBalances[req.FromAccountId] = 0.0 // Starting balance for new accounts
	}
	if _, ok := s.accountBalances[req.ToAccountId]; !ok {
		s.accountBalances[req.ToAccountId] = 0.0 // Starting balance for new accounts
	}

	switch req.Type {
	case pb.TransactionType_DEBIT:
		if s.accountBalances[req.FromAccountId] >= req.Amount {
			s.accountBalances[req.FromAccountId] -= req.Amount
			resp.Status = "SUCCESS"
			resp.Message = fmt.Sprintf("Debit of %.2f from account %s successful.", req.Amount, req.FromAccountId)
		} else {
			resp.Message = fmt.Sprintf("Insufficient funds in account %s for debit of %.2f.", req.FromAccountId, req.Amount)
		}
	case pb.TransactionType_CREDIT:
		s.accountBalances[req.ToAccountId] += req.Amount
		resp.Status = "SUCCESS"
		resp.Message = fmt.Sprintf("Credit of %.2f to account %s successful.", req.Amount, req.ToAccountId)
	case pb.TransactionType_TRANSFER:
		if req.FromAccountId == req.ToAccountId {
			resp.Message = "Cannot transfer to the same account."
		} else if s.accountBalances[req.FromAccountId] >= req.Amount {
			s.accountBalances[req.FromAccountId] -= req.Amount
			s.accountBalances[req.ToAccountId] += req.Amount
			resp.Status = "SUCCESS"
			resp.Message = fmt.Sprintf("Transfer of %.2f from %s to %s successful.", req.Amount, req.FromAccountId, req.ToAccountId)
		} else {
			resp.Message = fmt.Sprintf("Insufficient funds in account %s for transfer of %.2f.", req.FromAccountId, req.Amount)
		}
	default:
		resp.Message = "Unsupported transaction type."
	}

	s.transactions[transactionID] = resp
	log.Printf("Transaction %s: %s", transactionID, resp.Message)
	return resp, nil
}

// GetBalance implements transaction.TransactionServiceServer
func (s *server) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	balance, ok := s.accountBalances[req.AccountId]
	if !ok {
		// For simplicity, return 0 balance for non-existent accounts
		balance = 0.0
		log.Printf("Account %s not found, returning 0 balance.", req.AccountId)
	}

	resp := &pb.GetBalanceResponse{
		AccountId:   req.AccountId,
		Balance:     balance,
		Currency:    "USD", // Hardcoding currency for simplicity
		LastUpdated: timestamppb.New(time.Now()),
	}

	log.Printf("GetBalance for account %s: %.2f %s", req.AccountId, resp.Balance, resp.Currency)
	return resp, nil
}

