// client/main.go
package main

import (
	"context"
	"log"
	"time"

	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"

	pb "github.com/your-org/your-repo/pkg/transaction" // Adjust import path
)

const (
	address = "localhost:50051"
)

func main() {
	conn, err := grpc.Dial(address, grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		log.Fatalf("did not connect: %v", err)
	}
	defer conn.Close()
	c := pb.NewTransactionServiceClient(conn)

	ctx, cancel := context.WithTimeout(context.Background(), time.Second)
	defer cancel()

	// 1. Get initial balance for account A123
	balanceResp, err := c.GetBalance(ctx, &pb.GetBalanceRequest{AccountId: "A123"})
	if err != nil {
		log.Fatalf("could not get balance: %v", err)
	}
	log.Printf("Initial Balance for A123: %.2f %s", balanceResp.GetBalance(), balanceResp.GetCurrency())

	// 2. Credit account A123
	creditResp, err := c.CreateTransaction(ctx, &pb.CreateTransactionRequest{
		ToAccountId: "A123",
		Amount:      1000.00,
		Currency:    "USD",
		Type:        pb.TransactionType_CREDIT,
		Description: "Initial deposit",
	})
	if err != nil {
		log.Fatalf("could not credit: %v", err)
	}
	log.Printf("Credit Transaction: ID=%s, Status=%s, Message=%s", creditResp.GetTransactionId(), creditResp.GetStatus(), creditResp.GetMessage())

	// 3. Get updated balance for account A123
	balanceResp, err = c.GetBalance(ctx, &pb.GetBalanceRequest{AccountId: "A123"})
	if err != nil {
		log.Fatalf("could not get balance: %v", err)
	}
	log.Printf("Updated Balance for A123: %.2f %s", balanceResp.GetBalance(), balanceResp.GetCurrency())

	// 4. Transfer from A123 to B456
	transferResp, err := c.CreateTransaction(ctx, &pb.CreateTransactionRequest{
		FromAccountId: "A123",
		ToAccountId:   "B456",
		Amount:        250.50,
		Currency:      "USD",
		Type:          pb.TransactionType_TRANSFER,
		Description:   "Payment for services",
	})
	if err != nil {
		log.Fatalf("could not transfer: %v", err)
	}
	log.Printf("Transfer Transaction: ID=%s, Status=%s, Message=%s", transferResp.GetTransactionId(), transferResp.GetStatus(), transferResp.GetMessage())

	// 5. Check balances after transfer
	balanceRespA123, err := c.GetBalance(ctx, &pb.GetBalanceRequest{AccountId: "A123"})
	if err != nil {
		log.Fatalf("could not get balance for A123: %v", err)
	}
	log.Printf("Balance for A123 after transfer: %.2f %s", balanceRespA123.GetBalance(), balanceRespA123.GetCurrency())

	balanceRespB456, err := c.GetBalance(ctx, &pb.GetBalanceRequest{AccountId: "B456"})
	if err != nil {
		log.Fatalf("could not get balance for B456: %v", err)
	}
	log.Printf("Balance for B456 after transfer: %.2f %s", balanceRespB456.GetBalance(), balanceRespB456.GetCurrency())

	// 6. Attempt a debit with insufficient funds
	debitFailResp, err := c.CreateTransaction(ctx, &pb.CreateTransactionRequest{
		FromAccountId: "A123",
		Amount:        10000.00,
		Currency:      "USD",
		Type:          pb.TransactionType_DEBIT,
		Description:   "Large withdrawal attempt",
	})
	if err != nil {
		log.Fatalf("could not debit: %v", err)
	}
	log.Printf("Debit Fail Transaction: ID=%s, Status=%s, Message=%s", debitFailResp.GetTransactionId(), debitFailResp.GetStatus(), debitFailResp.GetMessage())
}